#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use URI;

my $cgi = CGI->new();

my $redirect_url = $cgi->param('next');

my @allowed_hosts = (
    'www.example.com',
    'app.example.com',
    'example.com',
);

my $default_url = '/dashboard';

sub is_valid_redirect {
    my ($url) = @_;

    return 0 unless defined $url && $url ne '';

    return 0 if $url =~ /[\r\n]/;

    if ($url =~ m{^/[^/\\]}i || $url eq '/') {
        return 1;
    }

    my $uri = eval { URI->new($url) };
    return 0 unless $uri;

    my $scheme = $uri->scheme // '';
    return 0 unless $scheme eq 'http' || $scheme eq 'https';

    my $host = eval { $uri->host } // '';
    return 0 unless $host;

    foreach my $allowed (@allowed_hosts) {
        if (lc($host) eq lc($allowed)) {
            return 1;
        }
    }

    return 0;
}

sub sanitize_url {
    my ($url) = @_;

    $url =~ s/[\r\n]//g;

    $url =~ s/[^\x20-\x7E]//g;

    return $url;
